query:
mutation CreateDocGeneration($input: CreateDocGenerationInput!) {
  createDocGeneration(input: $input) {
    ...DocGenerationFragment
    __typename
  }
}

fragment DocGenerationFragment on DocGeneration {
  id
  generationType
  userId
  workspaceId
  templateDocId
  draftInput {
    ...DocGenerateInputFragment
    __typename
  }
  docGenerateInputs {
    ...DocGenerateInputFragment
    __typename
  }
  createdTime
  updatedTime
  __typename
}

fragment DocGenerateInputFragment on DocGenerateInput {
  id
  docGenerationId
  interactionId
  status
  prompt
  content
  format
  settings
  docId
  docGenerateOutputId
  createdTime
  updatedTime
  __typename
}
